/**
 * Map Libraries Module
 *
 * This module exports all map-related libraries for use in the application.
 */

// Simple module that loads map libraries dynamically when needed
let mapLibrariesLoaded = false;
let georaster: any, parse: any, fromArrays: any, GeoRasterLayer: any;

// Function to load map libraries dynamically
export async function loadMapLibraries() {
  if (mapLibrariesLoaded) return { georaster, parse, fromArrays, GeoRasterLayer };

  try {
    console.log('Loading map libraries...');

    // Dynamic import of georaster
    const georasterModule = await import('georaster');
    georaster = georasterModule.default;
    parse = georasterModule.parse;
    fromArrays = georasterModule.fromArrays;

    // Dynamic import of GeoRasterLayer
    const geoRasterLayerModule = await import('georaster-layer-for-leaflet');
    GeoRasterLayer = geoRasterLayerModule.default;

    mapLibrariesLoaded = true;
    console.log('Map libraries loaded successfully');

    return { georaster, parse, fromArrays, GeoRasterLayer };
  } catch (error) {
    console.error('Failed to load map libraries:', error);
    throw error;
  }
}

// Export the loader function and provide fallback exports
export {
  georaster,
  fromArrays,
  parse,
  GeoRasterLayer
};
